VALUES
  ('dietitian-moex-09924', 'dietitian', 'dietitian-moex-095-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關學校餐廳廚房員生消費合作社衛生管理辦法之內容，下列那一項是錯誤的？', '["領有營養師執業執照者，可擔任學校辦理餐飲衛生業務督導人員", "擔任學校辦理餐飲衛生業務之督導人員，每學年應參加衛生（營養）講習至少十六小時", "高級中等以下學校供售之食品，以正餐、飲品、點心、水果為限", "學校應提供二家以上外購盒餐食品之廠商，以利學生選擇 （請接背面） 95年第二次專門職業及技術人員高等暨普通考試醫事人員、  全一張 （背面） 中醫師、心理師、呼吸治療師、營養師、獸醫人員考試試題 等    別 ：高等考試 類    科 ：營養師 科    目 ：公共衛生營養學"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "c3b653f2dce9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "095140", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "095", "exam_name": "095年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
